@RestController
@RequestMapping("/saml")
public class SamlController {

    private final SamlSpProperties props;
    private final SamlMessageBuilder messageBuilder;
    private final SamlResponseValidator responseValidator;
    private final SamlSessionRepository sessionRepository;

    public SamlController(SamlSpProperties props,
                          SamlMessageBuilder messageBuilder,
                          SamlResponseValidator responseValidator,
                          SamlSessionRepository sessionRepository) {
        this.props = props;
        this.messageBuilder = messageBuilder;
        this.responseValidator = responseValidator;
        this.sessionRepository = sessionRepository;
    }

    @GetMapping("/metadata")
    public String metadata() throws Exception {
        return messageBuilder.buildSpMetadataXml();
    }

    @GetMapping("/login")
    public void login(HttpServletResponse response) throws Exception {
        String relayState = UUID.randomUUID().toString();
        String requestId = "_" + UUID.randomUUID();
        String authnRequestXml = messageBuilder.buildAuthnRequestXml(requestId, Instant.now());

        sessionRepository.save(new SamlSession(relayState, requestId, Instant.now()));

        String samlRequest = messageBuilder.deflateAndBase64Encode(authnRequestXml);

        String redirect = props.idpSsoUrl()
                + (props.idpSsoUrl().contains("?") ? "&" : "?")
                + "SAMLRequest=" + url(samlRequest)
                + "&RelayState=" + url(relayState);

        response.setStatus(302);
        response.setHeader("Location", redirect);
    }

    @PostMapping(value = "/acs", consumes = MediaType.APPLICATION_FORM_URLENCODED_VALUE)
    public Map<String, Object> acs(@RequestParam("SAMLResponse") String samlResponse,
                                  @RequestParam(value = "RelayState", required = false) String relayState,
                                  HttpServletRequest request) throws Exception {

        SamlSession session = (relayState != null) ? sessionRepository.consume(relayState) : null;

        var result = responseValidator.validateAndExtract(samlResponse, session);

        return Map.of(
                "status", "OK",
                "nameId", result.nameId(),
                "sessionIndex", result.sessionIndex(),
                "attributes", result.attributes()
        );
    }

    @PostMapping(value = "/logout", consumes = MediaType.APPLICATION_FORM_URLENCODED_VALUE)
    public Map<String, Object> logout(@RequestParam MultiValueMap<String, String> form) {
        return Map.of("status", "NOT_IMPLEMENTED", "received", form);
    }

    private static String url(String s) {
        return URLEncoder.encode(s, StandardCharsets.UTF_8);
    }
}

