package com.example.saml.saml;

import org.springframework.stereotype.Component;

import java.time.Duration;
import java.time.Instant;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

@Component
public class InMemorySamlSessionRepository implements SamlSessionRepository {

    private final Map<String, SamlSession> store = new ConcurrentHashMap<>();
    private final Duration ttl = Duration.ofMinutes(10);

    @Override
    public void save(SamlSession session) {
        store.put(session.relayState(), session);
    }

    @Override
    public SamlSession consume(String relayState) {
        SamlSession s = store.remove(relayState);
        if (s == null) return null;
        if (Instant.now().isAfter(s.createdAt().plus(ttl))) return null;
        return s;
    }
}

