package com.example.saml.web;

import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@ControllerAdvice
public class GlobalExceptionHandler {

    @ExceptionHandler(SecurityException.class)
    public ResponseEntity<?> security(SecurityException e) {
        return ResponseEntity.status(HttpStatus.UNAUTHORIZED).body(java.util.Map.of(
                "status", "UNAUTHORIZED",
                "error", e.getMessage()
        ));
    }

    @ExceptionHandler(Exception.class)
    public ResponseEntity<?> other(Exception e) {
        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(java.util.Map.of(
                "status", "ERROR",
                "error", e.getMessage()
        ));
    }
}

package com.example.saml.config;

import org.springframework.boot.web.servlet.FilterRegistrationBean;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

import jakarta.servlet.*;
import jakarta.servlet.http.HttpServletRequest;
import java.io.IOException;

@Configuration
public class RequestLoggingFilterConfig {

    @Bean
    public FilterRegistrationBean<Filter> samlRequestLoggingFilter() {
        FilterRegistrationBean<Filter> bean = new FilterRegistrationBean<>();
        bean.setFilter(new Filter() {
            @Override public void init(FilterConfig filterConfig) {}
            @Override public void destroy() {}
            @Override
            public void doFilter(ServletRequest request, ServletResponse response, FilterChain chain) throws IOException, ServletException {
                HttpServletRequest r = (HttpServletRequest) request;
                chain.doFilter(request, response);
            }
        });
        bean.addUrlPatterns("/saml/*");
        bean.setOrder(10);
        return bean;
    }
}

